#!/usr/bin/env perl
use strict;  # Ensures all variables are declared and used in the script, preventing errors due to undefined variable or function calls etc..
use warnings;   # Helps find potential issues with code that may be unsafe. It'll warn about any undeclared but required vars/objects being accessed which can lead into runtime exceptions if not handled properly by developers (like in case of SQL queries). 
use CGI qw(:standard);    # Provides access to the query parameters via a hash reference, and also provides methods for accessing these params. It's part of Perl module 'CGI'.  

my $comment = param('text');     # Fetching comment text from parameter named "text". 
$comment =~ s/<\/*//g;    # Removing HTML tags using regex to sanitize the input. This is a simple example, in real world cases you might want more complex solution for removing html or javascript code etc..  
print header(-type => 'html'), qq(Content-Disposition: inline-block\n), "$comment";  # Printing HTML content with sanitized comment text. This will display the user's comments in an iframe block, and users can include basic html formatting (like div).